SELECT component_id, characteristic_id, test_condition_id, max_value
FROM component_characteristics
WHERE max_value > 5.0;

SELECT c.component_id, c.component_name
FROM components c
WHERE EXISTS (
    SELECT 1 FROM component_characteristic_revisions ccr
    WHERE ccr.component_id = c.component_id
)
OR EXISTS (
    SELECT 1 FROM component_test_condition_revisions ctr
    WHERE ctr.component_id = c.component_id
);

SELECT MAX(revision_date) AS latest_revision_date
FROM component_revisions
WHERE component_id = 1;

SELECT revision_date
FROM component_characteristic_revisions
WHERE component_id = 1 AND characteristic_id = 1;
